class UserService(
    private val userRepository: UserRepository,
    private val profileRepository: ProfileRepository,
    private val followRepository: FollowRepository,
) {

    // 조회: 캐시 히트 시 DB 미조회 (userProfile::userId 키로 저장)
    @Cacheable(
        cacheNames = [CacheNames.USER_PROFILE],
        key = "#userId",
    )
    fun getUserProfile(userId: String): UserProfileDto {
        // fetch join으로 N+1 제거 (db-query-helper 영역)
        val user = userRepository.findByIdWithProfile(userId)
            ?: throw NotFoundException("사용자를 찾을 수 없습니다: $userId")
        val followCount = followRepository.countByFollowingId(userId)
        return UserProfileDto.from(user, followCount)
        // 쿼리 3개 → 1개 / 응답시간 ~80ms → ~5ms (캐시 히트)
    }

    // 수정: 캐시 무효화
    @CacheEvict(
        cacheNames = [CacheNames.USER_PROFILE],
        key = "#userId",
    )
    @Transactional
    fun updateProfile(userId: String, request: UpdateProfileRequest): UserProfileDto {
        val user = userRepository.findById(userId).orElseThrow()
        user.updateProfile(request)
        return getUserProfile(userId)
    }
}
```

**예상 개선 수치:**
- 캐시 히트율 80% 가정 시 응답 시간: 80ms → 평균 20ms
- DB 쿼리 수: 3회 → 캐시 히트 시 0회

