### 3-4. 알림 설정 캐시 (변경 빈도 낮음, TTL 길게)

```kotlin
@Service
class NotificationSettingService(
    private val notificationSettingRepository: NotificationSettingRepository,
) {

    // 알림 설정은 자주 바뀌지 않으므로 TTL 1시간
    @Cacheable(
        cacheNames = [CacheNames.NOTIFICATION_SETTINGS],
        key = "#userId",
    )
    fun getSettings(userId: String): NotificationSettingDto {
        return notificationSettingRepository.findByUserId(userId)
            ?.let { NotificationSettingDto.from(it) }
            ?: NotificationSettingDto.default()
    }

    @CachePut(
        cacheNames = [CacheNames.NOTIFICATION_SETTINGS],
        key = "#userId",
    )
    @Transactional
    fun updateSettings(userId: String, request: UpdateNotificationRequest): NotificationSettingDto {
        // @CachePut: DB 저장 후 캐시도 최신 값으로 갱신 (Evict 후 재조회 불필요)
        val entity = notificationSettingRepository.findByUserId(userId)
            ?: NotificationSettingEntity(userId = userId)
        entity.update(request)
        notificationSettingRepository.save(entity)
        return NotificationSettingDto.from(entity)
    }
}
```

